const americanCharacters = [
  { id:'ashley-taylor', name:'Ashley Taylor', birthday:'20th January', gender:'Female', nationality:'US American', occupation:'Student', hair:'Blonde', eyes:'Blue', height:'176 cm / 5\'9"', weight:'63 kg / 139 lb', chest:'92 cm / 36"', waist:'64 cm / 25"', hips:'94 cm / 37"', firstAppearance:'Strange Behaviours', status:'alive', setting:'American Setting', stories:['Strange Behaviours','An American Nightmare'], victims:['Brian — Strange Behaviours (swallowed whole, at his own request)','Megan Sanders — Strange Behaviours (swallowed alive, lawyer investigating journalist disappearances)','Timothy Walker — Strange Behaviours (swallowed alive, convicted serial killer)','Max — An American Nightmare (swallowed alive, unknowingly — mistook him for a shrinkie)','Diane — A Matter of Principle (swallowed whole, shrunken woman begging for help)','Dylan — A Matter of Principle (swallowed whole, activist/terrorist, brother of Paige Wright)'], estimatedAnonymousKills:55, shrinkieCravings:90, cruelty:20, playfulness:55, intimateBehavior:5, supportsVortex:95, iconicQuote:'"I\'m a monster too!" — Ashley playfully snarling at a tiny before eating him, A Matter of Principle', bio:'Ashley Taylor is the primary predator character of Strange Behaviours and a key figure in the American Setting. She is a tall, very athletic blonde with piercing light blue eyes and a deeply tanned, fit physique — described as angelic-faced with a kind smile and perfectly straight white teeth. Cheerful, socially confident, and outwardly warm, she lives with her parents in a house in a warm coastal region of the US and is studying German as a sentimental connection to her late German grandmother Luise. Ashley is a fully normalised, enthusiastic VortexFoods™ consumer who shows no moral qualm about eating shrunken people. In Strange Behaviours, she purchases a full box of shrinkies alongside a hamburger and fries, consuming them casually while studying for a German language exam in her room. She has an unusual interaction with Brian, a vorarephile shrunken man who laughs uncontrollably when she is about to eat him. Genuinely curious and disarmed by his reaction, she pauses to speak with him, learns of his desire to be eaten, and ultimately honours his request to be swallowed whole. In An American Nightmare, Ashley meets Max at passport control at the airport — friendly and charming — then boards the plane without realising he has been shrunk and loaded into the Vortex catering supply. She eats him entirely unknowingly during the in-flight promotional dinner, never learning the truth.' },
  { id:'mary-taylor', name:'Mary Taylor', birthday:'7th March', gender:'Female', nationality:'US American', occupation:'Physician', hair:'Blonde', eyes:'Blue', height:'171 cm / 5\'8"', weight:'63 kg / 139 lb', chest:'92 cm / 36"', waist:'68 cm / 27"', hips:'95 cm / 37"', firstAppearance:'Strange Behaviours', status:'alive', setting:'American Setting', stories:['Strange Behaviours','An American Nightmare'], iconicQuote:'"Shrunken or not, those little beings ar... were human beings like you and me." — Mary Taylor, Strange Behaviours', bio:'Mary Taylor is Ashley\'s mother, a physician who is still fit and active for her age. She appears in Strange Behaviours as a quiet moral counterpoint to her daughter: Mary privately objects to VortexFoods™ on humanitarian grounds, believing shrunken people were and still are human beings regardless of legal status. She represents the older generation that remembers a time before the normalisation of shrinkies and still carries the ethical weight of that memory. In An American Nightmare, she welcomes Ashley home from Germany with an emotional reunion and prepares her favorite macaroni and cheese.' },
  { id:'robert-taylor', name:'Robert Taylor', birthday:'9th September', gender:'Male', nationality:'US American', occupation:'Coast Guard officer', hair:'Grey', eyes:'Blue', height:'186 cm / 6\'1"', weight:'90 kg / 198 lb', chest:'116 cm / 46"', waist:'94 cm / 37"', hips:'108 cm / 42"', firstAppearance:'Strange Behaviours', status:'alive', setting:'American Setting', stories:['Strange Behaviours','An American Nightmare'], iconicQuote:'"Ok." — Robert\'s characteristically terse text reply, An American Nightmare', bio:'Robert "Rob" Taylor is Ashley\'s father and a Coast Guard officer. At the time of Strange Behaviours, he is working long hours responding to a heightened security situation following the forced surfacing of an improvised narcotics submarine near the Mexican border. He is described as pragmatic and not particularly sympathetic to his wife Mary\'s moral reservations about VortexFoods™. In An American Nightmare, he picks Ashley up from the airport after her year abroad in Germany, driving her home in the family\'s white jeep.' },
  { id:'kayla-hayes', name:'Kayla Hayes', birthday:'12th July', gender:'Female', nationality:'US American', occupation:'Businesswoman (Vortex SCM)', hair:'Black', eyes:'Dark brown', height:'172 cm / 5\'8"', weight:'70 kg / 154 lb', chest:'98 cm / 39"', waist:'75 cm / 30"', hips:'103 cm / 41"', firstAppearance:'An American Nightmare', status:'alive', setting:'American Setting', stories:['An American Nightmare','A Matter of Principle'], victims:['Heiko Brandt — An American Nightmare (tossed into mouth, convicted violent criminal)'], estimatedAnonymousKills:3, shrinkieCravings:75, cruelty:30, playfulness:40, intimateBehavior:5, supportsVortex:100, iconicQuote:'"Watch me." — Kayla Hayes dismissing Seo-Yun\'s legal objections, A Matter of Principle', bio:'Kayla Hayes is a US American businesswoman employed by VortexFoods™ in Supply Chain Management. She is described as remarkably good-looking for her age with smooth, browned caramel skin, long black hair, and large dark brown eyes. She flies economy despite her corporate role, joking she is not important enough for the fancy seats. During dinner on the transatlantic flight she casually eats Heiko Brandt — tossing him into her mouth mid-conversation. She and Ashley bond briefly over the tickling sensation of live shrinkies in their stomachs.' },
  { id:'rachel-cohen', name:'Rachel Cohen', birthday:'15th March', gender:'Female', nationality:'US American', occupation:'Student', hair:'Black', eyes:'Green', height:'173 cm / 5\'8"', weight:'65 kg / 143 lb', chest:'96 cm / 38"', waist:'68 cm / 27"', hips:'100 cm / 39"', firstAppearance:'Strange Behaviours', status:'alive', setting:'American Setting', stories:['Strange Behaviours','A Matter of Principle','Good for Goodness\' Sake'], victims:['Miguel — A Matter of Principle (sucked in and swallowed alive, anti-Vortex activist)','Multiple anonymous shrinkies — A Matter of Principle (from medium box, casually consumed)'], estimatedAnonymousKills:47, shrinkieCravings:80, cruelty:15, playfulness:30, intimateBehavior:10, supportsVortex:75, iconicQuote:'"Bye, tiny bitch!" — Rachel waving Paige goodbye as Hannah swallows her, A Matter of Principle', bio:'Rachel Cohen is first referenced in Strange Behaviours as Ashley Taylor\'s close friend and is Hannah Lindquist\'s roommate. In A Matter of Principle, she nearly eats her former cafe co-worker Paige Wright by accident — recognising her just in time, horrified, before her sympathy evaporates upon learning Paige\'s group shot a security guard who was a new father. Rachel is a habitual, casual Vortex consumer who eats from her medium box throughout the meal with relaxed indifference. She refuses to make herself throw up to save Miguel, citing vanity and public setting. She does not taunt shrinkies but feels no remorse. She is well-off — father advises the governor, mother is a plastic surgeon. She drives a red convertible, films Hannah eating her first tiny, and shares the video on social media with amusement.' },
  { id:'hannah-lindquist', name:'Hannah Lindquist', birthday:'16th May', gender:'Female', nationality:'US American', occupation:'Student', hair:'Ash blonde', eyes:'Grey-blue', height:'152 cm / 5\'0"', weight:'44 kg / 97 lb', chest:'84 cm / 33"', waist:'60 cm / 24"', hips:'86 cm / 34"', firstAppearance:'A Matter of Principle', status:'alive', setting:'American Setting', stories:['A Matter of Principle',"Good for Goodness' Sake",'Checking Out'], victims:["Paige Wright — A Matter of Principle (swallowed whole, anti-Vortex activist — Hannah's first tiny)", 'Jordan — A Matter of Principle (swallowed whole, activist)', 'Tyler — A Matter of Principle (swallowed whole, activist/tech specialist)', "Anonymous German man — A Matter of Principle (from Rachel's box)", "Multiple anonymous shrinkies — A Matter of Principle (from Rachel's box, roughly half)", "Arthur — Good for Goodness' Sake (former classmate; used intimately, then swallowed whole)", 'Alex Baker — Checking Out (Monica\'s husband; chewed alive in cereal bite)', 'Monica Baker — Checking Out (state prosecutor\'s attorney investigating corruption; swallowed whole in cereal)', 'Unnamed dweebish young man — Checking Out (cereal tiny; shown to protagonist via webcam wink)', 'Multiple anonymous cereal shrinkies — Checking Out (eaten with fruity loops during video call with Victoria)'], estimatedAnonymousKills:16, shrinkieCravings:85, cruelty:40, playfulness:75, intimateBehavior:95, supportsVortex:65, iconicQuote:'"No. Just munching my cereal." — Hannah\'s deadpan reply to Victoria while swallowing a tiny on camera, Checking Out', bio:"Hannah Lindquist is a central character in the American Setting — a small, petite ash-blonde student with grey-blue eyes and a slight West Coast tan. She is the daughter of military officer William Lindquist and sister of Victoria and Ryan. In A Matter of Principle she eats her first shrinkie, consuming around a dozen in a single sitting with intense repressed arousal. In Good for Goodness' Sake she returns home for Christmas, inserting her former classmate Arthur into her vagina for intimate use before swallowing him whole while climaxing. In Checking Out, she appears via video call with Victoria during an early morning study session — casually eating a bowl of fruity loops cereal laced with shrinkies, swallowing them one by one mid-sentence. Most notably, she notices the protagonist staring helplessly from inside Victoria's Vortex box on the counter, and with a deadpan expression, tilts her spoon toward the camera to show a tiny about to be eaten — giving the protagonist a direct wink before swallowing him whole and answering Victoria's question as if nothing happened. This moment establishes Hannah as not only highly eroticised in her consumption but genuinely playful and performative about it, demonstrating an enjoyment that goes beyond arousal into theatrical cruelty. By this point she has devoured hundreds of people and is accelerating. She is planning a spa weekend with Rachel, Ashley, Emma, and possibly Rebecca." },
  { id:'elizabeth-lindquist', name:'Elizabeth Lindquist', birthday:'5th August', gender:'Female', nationality:'US American', occupation:'Military officer', hair:'Dark blonde', eyes:'Blue', height:'170 cm / 5\'7"', weight:'66 kg / 146 lb', chest:'92 cm / 36"', waist:'72 cm / 28"', hips:'98 cm / 38"', firstAppearance:'Good for Goodness\' Sake', status:'alive', setting:'American Setting', stories:['Good for Goodness\' Sake'], bio:'Elizabeth Lindquist is Hannah\'s sister and a military officer, following in their father William\'s footsteps.' },
  { id:'victoria-lindquist', name:'Victoria Lindquist', birthday:'8th March', gender:'Female', nationality:'US American', occupation:'Receptionist', hair:'Dark blonde', eyes:'Grey-blue', height:'170 cm / 5\'7"', weight:'60 kg / 132 lb', chest:'90 cm / 35"', waist:'62 cm / 24"', hips:'90 cm / 35"', firstAppearance:"Good for Goodness' Sake", status:'alive', setting:'American Setting', stories:["Good for Goodness' Sake",'Checking Out'], victims:["~12 anonymous shrinkies — Good for Goodness' Sake (grabbed from Hannah's plate at Christmas; ate one accidentally inside gingerbread)", 'Nicole Barnes — Checking Out (prison inmate; sucked like candy in elevator, swallowed in front of a young family)', 'Scott Chapman — Checking Out (fraudulent banker; first bath kill — played between cheeks, swallowed with hot chocolate)', 'Marcus Chen — Checking Out (arsonist firefighter; eaten during two-minute conditioner wait)', 'Harper Bennett — Checking Out (wildlife activist framed by a politician; flicked in and swallowed during conditioner rinse)', 'Checking Out Main Character — Checking Out (business traveller; swept into mouth by shark-dive from below bathwater, swallowed with soapy water)', 'Unnamed female buzz-cut shrinkie — Checking Out (swallowed with last cocoa gulp to prevent overnight escape)', '3–4 anonymous bath shrinkies — Checking Out (eaten casually between named kills)'], estimatedAnonymousKills:20, shrinkieCravings:70, cruelty:20, playfulness:35, intimateBehavior:5, supportsVortex:75, iconicQuote:'"No running off, okay? I know you\'re freaking out, but you\'re my food now." — Victoria to the remaining box after swallowing the protagonist, Checking Out', bio:"Victoria Lindquist is Hannah's older sister — nearly a head taller, with the same dark blonde hair and mysterious grey-blue eyes, the proportions of a Renaissance statue, and an effortless grace in every movement. She works night shifts as a hotel front-desk receptionist at the Grand Imperial, a job that has eroded her sleep schedule, her social life, and any real chance of meeting people. In Good for Goodness' Sake, she appears at home for Christmas, casually helping herself to a dozen tinies from Hannah's plate and accidentally biting through one tucked inside a piece of gingerbread. In Checking Out, she is the central predator. She gives the protagonist his 6 AM wake-up call, then processes his checkout with warm professionalism — both of them aware of a genuine mutual attraction they both feel but do not act on. The protagonist is stunned by a Vortex operative with a cattle prod in the hotel parking garage minutes later, and wakes up already shrunk in the staff room Vortex box. Victoria pockets the box on her way out without noticing him. She eats Nicole Barnes in an elevator on the way to her car — sucking on her like candy while a young family watches. At home she runs a lavender-scented bath, makes hot chocolate, and works through the box: Scott Chapman first (played in her cheek, swallowed); Marcus Chen and Harper Bennett during her conditioner wait; then the protagonist's escape attempt triggers the shark-dive — she submerges, erupts from beneath him mouth-open, scoops him in with a wave of bathwater, and swallows immediately with a wince at the soapy taste. She thumps her chest, says 'ew' to herself, then turns to the box and delivers the line calmly. She finishes the buzz-cut woman with her last cocoa and shelves the rest — Kyle Edwards included — for later. Victoria demonstrates real moral complexity: she grew up with her father's hunting ethic (clean kills, no gloating), felt acute guilt after her first Vortex experience as a teenager, and still feels a brief pang when shrinkies explicitly confess guilt. But she has internalised the school counsellor's argument that such empathy is misplaced and unhealthy, and suppresses it. She does not play with her food gratuitously — the shark-dive was partly about 'breaking in' the box, partly curiosity about a trick Stacy had described. Ryan and Stacy have been nudging her toward online dating. She gives Kyle to Stacy when she drops by for a forgotten scarf on Saturday." },
  { id:'william-lindquist', name:'William Lindquist', birthday:'19th October', gender:'Male', nationality:'US American', occupation:'Military officer', hair:'Ash blonde', eyes:'Grey-blue', height:'180 cm / 5\'11"', weight:'82 kg / 181 lb', chest:'106 cm / 42"', waist:'86 cm / 34"', hips:'100 cm / 39"', firstAppearance:"Good for Goodness' Sake", status:'alive', setting:'American Setting', stories:["Good for Goodness' Sake"], iconicQuote:'"Ope, my bad." — William nearly getting the car stuck in the snow, Good for Goodness\' Sake', bio:"William Lindquist is the patriarch of the Lindquist family and a military officer — the father of Hannah, Victoria, and Ryan. He drives Hannah home from the nearest major city after her long Christmas Eve travel day, nearly getting the car stuck backing into the snowy driveway. He is good-natured and warmly paternal, carrying Hannah's heavy suitcase upstairs and joking that she has been skipping classes to lie on the beach. He defers tidily to his wife's domestic authority and is a comfortable, unquestioning participant in the VortexFoods™ world order." },
  { id:'ryan-lindquist', name:'Ryan Lindquist', birthday:'14th February', gender:'Male', nationality:'US American', occupation:'Police officer', hair:'Ash blonde', eyes:'Grey-blue', height:'183 cm / 6\'0"', weight:'84 kg / 185 lb', chest:'108 cm / 43"', waist:'84 cm / 33"', hips:'100 cm / 39"', firstAppearance:"Good for Goodness' Sake", status:'alive', setting:'American Setting', stories:["Good for Goodness' Sake"], iconicQuote:'"[Coming home from his shift at the precinct on Christmas Eve]" — Ryan Lindquist, Good for Goodness\' Sake', bio:"Ryan Lindquist is the eldest of the Lindquist siblings and a serving police officer. He works a Christmas Eve shift at the precinct and arrives home slightly later than expected, joining the family for the julbord buffet. He shares the same ash-blonde hair and grey-blue eyes as his sisters. His role in the story is brief — a warm familial presence at the dinner table — but his career choice grounds the Lindquist family firmly within the institutional order that enables VortexFoods™ to operate." },
  { id:'mark-campbell', name:'Mark Campbell', birthday:'19th November', gender:'Male', nationality:'US American', occupation:'Paramilitary officer (Vortex)', hair:'Grey', eyes:'Blue', height:'185 cm / 6\'1"', weight:'89 kg / 196 lb', chest:'114 cm / 45"', waist:'88 cm / 35"', hips:'100 cm / 40"', firstAppearance:'A Matter of Principle', status:'alive', setting:'American Setting', stories:['A Matter of Principle'], shrinkieCravings:30, cruelty:50, playfulness:10, intimateBehavior:5, supportsVortex:90, iconicQuote:'"Mr. Campbell, take them to processing." — Kayla Hayes addressing him, A Matter of Principle', bio:'Mark Campbell is a military buzz-cut paramilitary officer in the employ of VortexFoods™, commanding the security detail of black SUVs that traps Paige Wright and her activist group in the parking garage of the processing facility. He is weary and professional — slightly surprised when Kayla Hayes exits the vehicle herself, but deferential to her authority. He oversees the handcuffing of the activists and receives the order to take them to processing. He represents the institutional muscle that enforces Vortex\'s will.' },
  { id:'seo-yun-park', name:'Seo-Yun Park', birthday:'9th March', gender:'Female', nationality:'US American', occupation:'Attorney (Vortex Legal)', hair:'Black', eyes:'Dark brown', height:'162 cm / 5\'4"', weight:'52 kg / 115 lb', chest:'84 cm / 33"', waist:'62 cm / 24"', hips:'88 cm / 35"', firstAppearance:'A Matter of Principle', status:'alive', setting:'American Setting', stories:['A Matter of Principle'], shrinkieCravings:10, cruelty:5, playfulness:5, intimateBehavior:5, supportsVortex:60, iconicQuote:'"I graduated top of my class in law school last year, Paige. Did you think I would throw all that away over some dead-end political cause?" — Seo-Yun Park, A Matter of Principle', bio:'Seo-Yun Park graduated top of her law school class and was previously embedded as an informant inside Paige Wright\'s activist group, providing Kayla Hayes with advance intelligence on the raid on the Vortex processing facility. She believed she had negotiated a deal for her comrades to face a proper trial, but Kayla dismisses this with contempt. Seo-Yun declines Kayla\'s offer to personally eat her former friends — calling it \'a bit much\' — and instead watches with visible discomfort as they are taken to processing. Despite her clear moral unease, she ultimately accepts her position in Vortex\'s legal department and is welcomed to the team. She represents the compromised idealist: someone who rationalised betrayal as pragmatism and must now live with the consequences.' },
  { id:'maria-reyes-ortega', name:'Maria Reyes Ortega', birthday:'30th July', gender:'Female', nationality:'Mexican', occupation:'Salesclerk (Vortex)', hair:'Black', eyes:'Dark brown', height:'159 cm / 5\'3"', weight:'55 kg / 120 lb', chest:'90 cm / 35"', waist:'67 cm / 26"', hips:'93 cm / 37"', firstAppearance:'A Matter of Principle', status:'alive', setting:'American Setting', stories:['A Matter of Principle'], shrinkieCravings:55, cruelty:5, playfulness:10, intimateBehavior:5, supportsVortex:70, iconicQuote:'"Neither had I before I came to the US. They\'re more afraid of you than you are of them." — María to Hannah about eating shrinkies, A Matter of Principle', bio:'María is a remarkably good-looking Latina salesclerk at the beachfront Vortex restaurant, described as having a strong Mexican accent and a warm, welcoming demeanour. She serves Hannah, Rachel, and Ashley at the counter, cheerfully noting that she herself had never eaten shrinkies before coming to the US. She casually packages Paige Wright\'s box as Rachel\'s order and handles the transaction with professional indifference, reminding the customers to return any leftover boxes — a policy that takes on sinister significance later in the story.' },
  { id:'cassandra-davis', name:'Cassandra Davis', birthday:'2nd July', gender:'Female', nationality:'US American', occupation:'Receptionist', hair:'Black', eyes:'Dark brown', height:'166 cm / 5\'5"', weight:'62 kg / 137 lb', chest:'92 cm / 36"', waist:'71 cm / 28"', hips:'97 cm / 38"', firstAppearance:'Checking Out', status:'alive', setting:'American Setting', stories:['Checking Out'], victims:['Joe Gunderson — Checking Out (convicted car thief; dismissed mid-plea and eaten with morning coffee)', 'Multiple anonymous shrinkies — Checking Out (consumed from box during morning break)'], estimatedAnonymousKills:8, shrinkieCravings:65, cruelty:10, playfulness:10, intimateBehavior:5, supportsVortex:75, iconicQuote:'"Sorry, no time to chat with strangers. I\'m sure you\'re a great guy and all, blah blah, yadda yadda. But I gotta have breakfast before my shift starts. Bye!" — Cassandra dismissing Joe Gunderson, Checking Out', bio:"Cassandra Davis is a Black American hotel receptionist who works morning shifts at the Grand Imperial alongside Victoria Lindquist. She comes across as outgoing, warm, and very easygoing. In Checking Out, she relieves Victoria after the night shift and is seen eating shrinkies from the staff's complimentary Vortex delivery with her morning coffee. She dismisses Joe Gunderson's attempt to reason with her with characteristic cheerful indifference — he briefly catches her attention by using her name, but when he turns out to be a stranger she doesn't know, she simply pops him in her mouth and washes him down with coffee. She eats the rest of her box casually over her break, occasionally finishing them between sips. She is clearly a habitual, normalised consumer with no cruelty but zero hesitation." },
  { id:'megan-smith', name:'Megan Smith', birthday:'19th June', gender:'Female', nationality:'US American', occupation:'Flight attendant', hair:'Blonde', eyes:'Green', height:'170 cm / 5\'7"', weight:'58 kg / 128 lb', chest:'88 cm / 35"', waist:'64 cm / 25"', hips:'90 cm / 35"', firstAppearance:'An American Nightmare', status:'alive', setting:'American Setting', stories:['An American Nightmare'], iconicQuote:'"I\'m on a diet." — Megan declining Kelly\'s offer of shrinkies, An American Nightmare', bio:'Megan Smith is Kelly Lewis\'s colleague on the transatlantic flight in An American Nightmare. Slightly chubby and bespectacled, she is seen working in the galley alongside Kelly. When Kelly offers her the Vortex snack box, Megan declines, saying she is on a diet.' },
  { id:'kelly-lewis', name:'Kelly Lewis', birthday:'2nd August', gender:'Female', nationality:'US American', occupation:'Flight attendant', hair:'Dark blonde', eyes:'Grey-green', height:'169 cm / 5\'7"', weight:'61 kg / 124 lb', chest:'94 cm / 37"', waist:'66 cm / 26"', hips:'98 cm / 39"', firstAppearance:'An American Nightmare', status:'alive', setting:'American Setting', stories:['An American Nightmare'], victims:['Thilo Busch — An American Nightmare (swallowed whole, journalist on Vortex hit list)','Anonymous woman — An American Nightmare (swallowed whole immediately after Thilo)'], estimatedAnonymousKills:5, shrinkieCravings:80, cruelty:10, playfulness:20, intimateBehavior:5, supportsVortex:70, iconicQuote:'"Don\'t mind if I do." — Kelly reaching for a Vortex box in the galley, An American Nightmare', bio:'Kelly Lewis is a US American flight attendant working transatlantic long-haul routes. She is described as exceptionally attractive for her age, with dark blonde hair and slightly mysterious grey-green eyes. She has a noticeable Southern drawl. Kelly is a habitual, casual VortexFoods™ consumer who snacks on shrinkies from the Vortex catering supply in the galley between service rounds. She eats Thilo Busch — a German journalist whom Vortex had targeted for his planned reporting on a Peruvian recruitment agency acting on their behalf — directly from a small promotional box. From Max\'s perspective inside the catering trolley, Kelly is a terrifying, godlike figure whose heels cause earthquakes.' },
  { id:'meryl-douglas', name:'Meryl Douglas', birthday:'12th March', gender:'Female', nationality:'US American', occupation:'Fitness coach', hair:'Dark brown', eyes:'Dark brown', height:'173 cm / 5\'8"', weight:'71 kg / 157 lb', chest:'94 cm / 37"', waist:'68 cm / 27"', hips:'98 cm / 39"', firstAppearance:'Conversations with Cuisine (canon guest)', status:'alive', setting:'American Setting', stories:['Conversations with Cuisine'], bio:'Meryl Douglas is an American fitness coach appearing in the canon guest story Conversations with Cuisine by Marius-the-Mage.' },
];

