// ─── UTILITY FUNCTIONS ────────────────────────────────────────────────────────

function badgeHTML(status) {
  if (status === 'alive') return '<span class="badge b-alive">Alive</span>';
  if (status === 'deceased') return '<span class="badge b-dec">Deceased</span>';
  return '<span class="badge b-unk">Unknown</span>';
}

function makeStoryCard(story, setting) {
  return `<div class="story-card">
    <div class="sc-meta">${setting} · Story ${story.order}</div>
    <div class="sc-title">${story.title}</div>
    <div class="sc-chars">Characters: ${story.chars.join(', ')}</div>
    <div class="sc-desc">${story.desc}</div>
  </div>`;
}

function makeCharCard(char) {
  return `<a class="char-card" href="characters.html#${char.id}">
    <div class="cc-name">${char.name}</div>
    <div class="cc-nat">${char.nationality}</div>
    <div class="cc-role">${char.occupation}</div>
    ${badgeHTML(char.status)}
  </a>`;
}

function allCharacters() {
  return [...germanCharacters, ...americanCharacters, ...guestCharacters, ...shrunkenVictims];
}
